var e=[{id:`L2_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`크륵......! 컥......!`,JPN:`ぐっ……！　くそっ……！`,ENG:`Hngh...! Ack...!`,TWN:`咳咳……！咳……！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`어, 어째서......?`,JPN:`な、なんだと……？`,ENG:`H-how...?`,TWN:`為、為什麼……?`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`어째서 시작형 따위의 반편이들에게...... 완성형인 내가......?`,JPN:`どうして試作形の出来損ないどもに……完成形のアタシが……？`,ENG:`How could a bunch of half-wit preliminary forms... But I'm perfect...`,TWN:`為什麼對付這些初始體的蠢貨們……身為完全體的我會……？`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`지금이야! 알트 소대!`,JPN:`今だ！　アルト小隊！`,ENG:`...Now! ALT Squad!`,TWN:`就是現在！阿爾特小隊！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`집중사격 개시!`,JPN:`集中射撃を開始！`,ENG:`Light her up!`,TWN:`開始集中射擊！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`크어억! ......크악!`,JPN:`ぐああ！　……くっ！`,ENG:`Kaaaaaaagh! ...Ack!`,TWN:`唔啊啊！……啊啊！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`우, 웃기지 마라! 이런 장난감 따위로 감히 나를......!`,JPN:`わ、笑わせるな！　こんなオモチャなんかで、よくもアタシを……！`,ENG:`Don't fool yourselves! You think your little toys can hurt me...?`,TWN:`開、開什麼玩笑了！ 這種玩具怎麼可能把我……！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`......그럼 이건 어때?!`,JPN:`……じゃあ、これはどう！？`,ENG:`...Then what about this?!`,TWN:`……那這個怎麼樣？！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`그건......?`,JPN:`それは……？`,ENG:`That...?`,TWN:`那是……？！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`뭐, 뭐야? 그거 설마 구 관리국의 레거시 디바이스......?`,JPN:`な、何だ？　まさか、旧管理局のレガシーデバイス……？`,ENG:`W-what? A legacy device from the Old Administration...?`,TWN:`什、什麼？那該不會是舊管理局的遺物吧？`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`에이미의 복수다!`,JPN:`エイミーの復讐だ！`,ENG:`This is for Amy!!!`,TWN:`艾米的死！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`이거나 처먹어!!`,JPN:`これでも食らえ！！`,ENG:`Go to hell!!!`,TWN:`妳就用這個付出代價吧！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`안...... 돼......`,JPN:`イ……ヤ……`,ENG:`Noooo... This can't be........`,TWN:`啊……不！！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`안 돼 안 돼 안 돼애애애애!!!`,JPN:`イヤ、イヤ、イヤああああーーーー！`,ENG:`NO, NO, NOOOOOOOOOO!!!`,TWN:`不要、不要，不要不要不要————啊啊啊！！！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`버리지 말아 줘! 버리지 말아 주세요!`,JPN:`見捨てないで！　見捨てないでください！`,ENG:`Don't forsake me! Please do not forsake me!`,TWN:`不要拋棄我，請不要拋棄我！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`KNIGHT_REPLACER_NULL_TRANS`,text:{KOREA:`저도, 부디 저도 약속의 땅에......!`,JPN:`アタシも、どうかアタシも約束の地に……！`,ENG:`Please take me to the promised land...`,TWN:`我也……一定要在應許之地上……！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`KNIGHT_REPLACER_NULL_TRANS`,face:`UNIT_IDLE`},R:null}}}];export{e as default};